def message(title, text, icon=MB_ICONINFORMATION, owner=None):
    user32.MessageBoxW(owner or main_hwnd or 0, str(text), title, MB_OK | icon)

def hide_console():
    try:
        hwnd = kernel32.GetConsoleWindow()
        if hwnd:
            user32.ShowWindow(hwnd, SW_HIDE)
    except Exception:
        pass

def set_dpi_awareness():
    try:
        # DPI_AWARENESS_CONTEXT_PER_MONITOR_AWARE_V2 == -4
        user32.SetProcessDpiAwarenessContext(ctypes.c_void_p(-4))
    except Exception:
        try:
            user32.SetProcessDPIAware()
        except Exception:
            pass

def ensure_windows_11():
    info = OSVERSIONINFOEXW()
    info.dwOSVersionInfoSize = ctypes.sizeof(info)
    if ntdll.RtlGetVersion(ctypes.byref(info)) != 0:
        raise OSError("无法读取 Windows 版本。")
    if info.dwMajorVersion < 10 or info.dwBuildNumber < 22000:
        raise OSError(f"需要 Windows 11（检测到版本 {info.dwMajorVersion}.{info.dwMinorVersion}.{info.dwBuildNumber}）。")

def acquire_mutex():
    global mutex_handle
    mutex_handle = kernel32.CreateMutexW(None, False, "Local\\AnyGameAIInstaller_v2")
    if not mutex_handle:
        raise ctypes.WinError(ctypes.get_last_error())
    if ctypes.get_last_error() == ERROR_ALREADY_EXISTS:
        raise RuntimeError("另一个 AnyGameAI 安装器正在运行。")

def com_method(obj, index, restype, *argtypes):
    vtbl = ctypes.cast(obj, ctypes.POINTER(ctypes.POINTER(ctypes.c_void_p))).contents
    addr = vtbl[index]
    return ctypes.WINFUNCTYPE(restype, ctypes.c_void_p, *argtypes)(addr)

def release_com(obj):
    if obj:
        com_method(obj, 2, ctypes.c_ulong)(obj)

def pick_folder(owner):
    # Modern IFileOpenDialog with FOS_PICKFOLDERS.
    clsid = GUID.from_string("DC1C5A9C-E88A-4DDE-A5A1-60F82A20AEF7")
    iid = GUID.from_string("D57C7288-D4AD-4768-BE02-9D969532D960")
    dialog = ctypes.c_void_p()
    hr = ole32.CoCreateInstance(ctypes.byref(clsid), None, CLSCTX_INPROC_SERVER, ctypes.byref(iid), ctypes.byref(dialog))
    if hr < 0:
        raise OSError(f"无法创建 IFileDialog（HRESULT 0x{hr & 0xffffffff:08X}）。")
    result = ctypes.c_void_p()
    shell_item = None
    try:
        get_options = com_method(dialog, 10, ctypes.c_long, ctypes.POINTER(wt.DWORD))
        set_options = com_method(dialog, 9, ctypes.c_long, wt.DWORD)
        set_title = com_method(dialog, 17, ctypes.c_long, wt.LPCWSTR)
        show_dialog = com_method(dialog, 3, ctypes.c_long, wt.HWND)
        get_result = com_method(dialog, 20, ctypes.c_long, ctypes.POINTER(ctypes.c_void_p))
        options = wt.DWORD()
        hr = get_options(dialog, ctypes.byref(options))
        if hr < 0:
            raise OSError("IFileDialog.GetOptions 失败。")
        hr = set_options(dialog, options.value | FOS_PICKFOLDERS | FOS_FORCEFILESYSTEM | FOS_PATHMUSTEXIST | FOS_DONTADDTORECENT)
        if hr < 0:
            raise OSError("IFileDialog.SetOptions 失败。")
        set_title(dialog, "选择 AnyGameAI 的安装位置（将在其中创建 AnyGameAI 文件夹）")
        hr = show_dialog(dialog, owner)
        if hr == HRESULT_CANCELLED:
            return None
        if hr < 0:
            raise OSError(f"文件夹选择失败（HRESULT 0x{hr & 0xffffffff:08X}）。")
        hr = get_result(dialog, ctypes.byref(result))
        if hr < 0 or not result:
            raise OSError("IFileDialog.GetResult 失败。")
        shell_item = result
        get_name = com_method(shell_item, 5, ctypes.c_long, wt.DWORD, ctypes.POINTER(ctypes.c_wchar_p))
        raw_path = ctypes.c_wchar_p()
        hr = get_name(shell_item, SIGDN_FILESYSPATH, ctypes.byref(raw_path))
        if hr < 0 or not raw_path.value:
            raise OSError("无法读取所选文件夹路径。")
        path = raw_path.value
        ole32.CoTaskMemFree(ctypes.cast(raw_path, ctypes.c_void_p))
        return path
    finally:
        release_com(shell_item)
        release_com(dialog)

def set_status(text):
    if status_edit:
        user32.SetWindowTextW(status_edit, text)

def set_edit_text(hwnd, text):
    user32.SetWindowTextW(hwnd, text)

def get_edit_text(hwnd):
    length = user32.GetWindowTextLengthW(hwnd)
    buf = ctypes.create_unicode_buffer(length + 1)
    user32.GetWindowTextW(hwnd, buf, length + 1)
    return buf.value

def is_root(path):
    p = Path(path)
    return p == Path(p.anchor)

def existing_ancestors(path):
    p = Path(path)
    parts = []
    while True:
        if p.exists():
            parts.append(p)
        if p.parent == p:
            break
        p = p.parent
    return parts

def has_reparse_point(path):
    for p in existing_ancestors(path):
        attrs = kernel32.GetFileAttributesW(str(p))
        if attrs != INVALID_FILE_ATTRIBUTES and attrs & FILE_ATTRIBUTE_REPARSE_POINT:
            return True
    return False

def normalize_case(path):
    return os.path.normcase(os.path.abspath(path)).rstrip("\\/")

def validate_location(parent, target):
    raw_parent = Path(parent)
    target = Path(target)
    if has_reparse_point(raw_parent) or (target.exists() and has_reparse_point(target)):
        raise ValueError("拒绝安装到重解析点、符号链接或联接目录。")
    parent = raw_parent.resolve(strict=True)
    if is_root(parent):
        raise ValueError("不能选择磁盘根目录。请选择普通文件夹。")
    windows_dir = normalize_case(os.environ.get("WINDIR", r"C:\\Windows"))
    dangerous = [windows_dir, normalize_case(os.path.join(windows_dir, "System32")), normalize_case(os.path.join(Path(parent).anchor, "$Recycle.Bin")), normalize_case(os.path.join(Path(parent).anchor, "Recovery"))]
    pnorm = normalize_case(parent)
    tnorm = normalize_case(target)
    for d in dangerous:
        if pnorm == d or pnorm.startswith(d + os.sep) or tnorm == d or tnorm.startswith(d + os.sep):
            raise ValueError("拒绝安装到 Windows 系统、回收站或恢复目录。")
    if target.name.rstrip(" .").upper() in {"CON", "PRN", "AUX", "NUL", "COM1", "LPT1"}:
        raise ValueError("安装目录名称无效。")
    # Test write permission without leaving data behind.
    probe = parent / f".anygameai_write_test_{os.getpid()}.tmp"
    try:
        with open(probe, "xb") as f:
            f.write(b"write-test")
            f.flush()
            os.fsync(f.fileno())
    finally:
        try:
            probe.unlink()
        except FileNotFoundError:
            pass
    free = ctypes.c_ulonglong()
    total = ctypes.c_ulonglong()
    total_free = ctypes.c_ulonglong()
    if not kernel32.GetDiskFreeSpaceExW(str(parent), ctypes.byref(free), ctypes.byref(total), ctypes.byref(total_free)):
        raise ctypes.WinError(ctypes.get_last_error())
    required = max(150 * 1024 * 1024, EXE_SIZE * 4)
    if free.value < required:
        raise OSError(f"可用空间不足：至少需要 {required // (1024*1024)} MB。")
    return parent, target

def browse():
    global selected_parent, install_path, confirmed
    chosen = pick_folder(main_hwnd)
    if not chosen:
        return
    selected_parent = Path(chosen)
    install_path = selected_parent / APP_NAME
    confirmed = False
    set_edit_text(path_edit, str(install_path))
    set_status("已选择路径。请点击“确认”执行安全检查；仍可点击“重新选择”。")
    user32.EnableWindow(confirm_button, True)
    user32.EnableWindow(install_button, False)
    set_edit_text(browse_button, "重新选择")

def confirm_path():
    global confirmed, selected_parent, install_path
    shown = get_edit_text(path_edit).strip()
    if not selected_parent or not shown:
        raise ValueError("请先选择安装位置。")
    if normalize_case(shown) != normalize_case(install_path):
        raise ValueError("路径文本已变化，请点击“重新选择”后使用文件夹选择器。")
    selected_parent, install_path = validate_location(selected_parent, install_path)
    confirmed = True
    user32.EnableWindow(install_button, True)
    set_status(f"路径检查通过：{install_path}\r\n点击“安装”。覆盖安装会先备份旧目录，成功后再删除备份。")

def payload_bytes():
    data = zlib.decompress(base64.b64decode(PAYLOAD))
    if len(data) != EXE_SIZE:
        raise RuntimeError("内嵌 EXE 大小校验失败。")
    digest = hashlib.sha256(data).hexdigest()
    if digest.lower() != EXE_SHA256:
        raise RuntimeError("内嵌 EXE SHA-256 校验失败。")
    return data

def write_atomic(path, data):
    tmp = path.with_name(path.name + ".tmp")
    with open(tmp, "wb") as f:
        f.write(data)
        f.flush()
        os.fsync(f.fileno())
    os.replace(tmp, path)

def hash_file(path):
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()

def perform_install():
    global installed
    if not confirmed or not install_path:
        raise RuntimeError("请先确认安装路径。")
    validate_location(selected_parent, install_path)
    data = payload_bytes()
    target = Path(install_path)
    backup = None
    set_status("正在准备安装并创建回滚点……")
    try:
        if target.exists():
            if has_reparse_point(target):
                raise ValueError("现有安装目录是重解析点，拒绝覆盖。")
            backup = target.with_name(target.name + ".backup-" + time.strftime("%Y%m%d-%H%M%S"))
            if backup.exists():
                raise FileExistsError(f"备份目录已存在：{backup}")
            os.replace(target, backup)
        target.mkdir(parents=True, exist_ok=False)
        (target / "data" / "games" / "DefaultGame" / "frames").mkdir(parents=True)
        (target / "data" / "games" / "DefaultGame" / "models").mkdir(parents=True)
        set_status("正在写入 AnyGameAI.exe……")
        exe_path = target / EXE_NAME
        write_atomic(exe_path, data)
        write_atomic(target / "README.txt", README_TEXT.encode("utf-8-sig"))
        manifest = {
            "name": APP_NAME,
            "version": APP_VERSION,
            "exe": EXE_NAME,
            "sha256": EXE_SHA256,
            "portable": True,
            "installed_at": time.strftime("%Y-%m-%dT%H:%M:%S%z"),
        }
        write_atomic(target / "VERSION.json", json.dumps(manifest, ensure_ascii=False, indent=2).encode("utf-8"))
        set_status("正在执行落盘 SHA-256 校验……")
        installed_hash = hash_file(exe_path)
        if installed_hash.lower() != EXE_SHA256:
            raise RuntimeError(f"落盘 EXE SHA-256 不一致：{installed_hash}")
        if backup:
            shutil.rmtree(backup)
            backup = None
        installed = True
        user32.EnableWindow(install_button, False)
        user32.EnableWindow(confirm_button, False)
        user32.EnableWindow(browse_button, False)
        user32.EnableWindow(finish_button, True)
        set_status(f"安装成功：{target}\r\nSHA-256：{installed_hash}\r\n该 AnyGameAI 文件夹可复制到其他 Windows 11 电脑直接运行。")
        message("安装成功", "AnyGameAI 已安装完成，并通过 SHA-256 校验。", MB_ICONINFORMATION)
    except Exception:
        # Automatic rollback: remove incomplete new install, then restore old directory.
        try:
            if target.exists():
                shutil.rmtree(target)
        finally:
            if backup and backup.exists():
                os.replace(backup, target)
        raise

def install_clicked():
    user32.EnableWindow(install_button, False)
    user32.EnableWindow(browse_button, False)
    user32.EnableWindow(confirm_button, False)
    try:
        perform_install()
    except Exception:
        user32.EnableWindow(browse_button, True)
        user32.EnableWindow(confirm_button, True)
        if confirmed:
            user32.EnableWindow(install_button, True)
        raise

def child(cls, text, style, x, y, w, h, cid):
    hwnd = user32.CreateWindowExW(0, cls, text, style, x, y, w, h, main_hwnd, cid, kernel32.GetModuleHandleW(None), None)
    if not hwnd:
        raise ctypes.WinError(ctypes.get_last_error())
    user32.SendMessageW(hwnd, WM_SETFONT, font, True)
    return hwnd

def wndproc(hwnd, msg, wparam, lparam):
    try:
        if msg == WM_COMMAND:
            cid = int(wparam & 0xFFFF)
            if cid == 101:
                browse()
            elif cid == 102:
                confirm_path()
            elif cid == 103:
                install_clicked()
            elif cid == 104:
                user32.DestroyWindow(hwnd)
            return 0
        if msg == WM_CLOSE:
            user32.DestroyWindow(hwnd)
            return 0
        if msg == WM_DESTROY:
            user32.PostQuitMessage(0)
            return 0
    except Exception:
        message("报错", traceback.format_exc(), MB_ICONERROR, hwnd)
    return user32.DefWindowProcW(hwnd, msg, wparam, lparam)

_wndproc = WNDPROC(wndproc)

def create_window():
    global main_hwnd, font, path_edit, status_edit, browse_button, confirm_button, install_button, finish_button
    hinst = kernel32.GetModuleHandleW(None)
    font = gdi32.GetStockObject(DEFAULT_GUI_FONT)
    wc = WNDCLASSW()
    wc.lpfnWndProc = _wndproc
    wc.hInstance = hinst
    wc.hCursor = user32.LoadCursorW(None, ctypes.cast(ctypes.c_void_p(IDC_ARROW), wt.LPCWSTR))
    wc.hbrBackground = wt.HBRUSH(COLOR_WINDOW + 1)
    wc.lpszClassName = CLASS_NAME
    atom = user32.RegisterClassW(ctypes.byref(wc))
    if not atom and ctypes.get_last_error() != 1410:
        raise ctypes.WinError(ctypes.get_last_error())
    w, h = 760, 410
    x = (user32.GetSystemMetrics(0) - w) // 2
    y = (user32.GetSystemMetrics(1) - h) // 2
    main_hwnd = user32.CreateWindowExW(0, CLASS_NAME, "AnyGameAI 安装程序 2.0", WS_CAPTION | WS_SYSMENU | WS_MINIMIZEBOX, x, y, w, h, None, None, hinst, None)
    if not main_hwnd:
        raise ctypes.WinError(ctypes.get_last_error())
    child("STATIC", "AnyGameAI 安装程序", WS_CHILD | WS_VISIBLE, 28, 20, 400, 30, 0)
    child("STATIC", "安装位置（自动创建 AnyGameAI 文件夹）", WS_CHILD | WS_VISIBLE, 28, 67, 350, 24, 0)
    path_edit = child("EDIT", "", WS_CHILD | WS_VISIBLE | WS_BORDER | ES_READONLY, 28, 96, 550, 30, 100)
    browse_button = child("BUTTON", "浏览", WS_CHILD | WS_VISIBLE | WS_TABSTOP, 594, 96, 120, 30, 101)
    confirm_button = child("BUTTON", "确认", WS_CHILD | WS_VISIBLE | WS_TABSTOP, 354, 151, 105, 34, 102)
    install_button = child("BUTTON", "安装", WS_CHILD | WS_VISIBLE | WS_TABSTOP, 474, 151, 105, 34, 103)
    finish_button = child("BUTTON", "完成", WS_CHILD | WS_VISIBLE | WS_TABSTOP, 594, 151, 120, 34, 104)
    status_edit = child("EDIT", "请点击“浏览”选择安装位置。", WS_CHILD | WS_VISIBLE | WS_BORDER | ES_READONLY | ES_MULTILINE | ES_AUTOVSCROLL, 28, 215, 686, 105, 105)
    user32.EnableWindow(confirm_button, False)
    user32.EnableWindow(install_button, False)
    user32.EnableWindow(finish_button, False)
    user32.ShowWindow(main_hwnd, SW_SHOW)
    user32.UpdateWindow(main_hwnd)
    msg = MSG()
    while True:
        result = user32.GetMessageW(ctypes.byref(msg), None, 0, 0)
        if result == -1:
            raise ctypes.WinError(ctypes.get_last_error())
        if result == 0:
            break
        user32.TranslateMessage(ctypes.byref(msg))
        user32.DispatchMessageW(ctypes.byref(msg))

def main():
    global ole_initialized
    hide_console()
    set_dpi_awareness()
    ensure_windows_11()
    acquire_mutex()
    hr = ole32.OleInitialize(None)
    if hr < 0:
        raise OSError(f"OleInitialize 失败（HRESULT 0x{hr & 0xffffffff:08X}）。")
    ole_initialized = True
    create_window()

try:
    main()
except Exception:
    message("AnyGameAI 安装器报错", traceback.format_exc(), MB_ICONERROR)
finally:
    if ole_initialized:
        ole32.OleUninitialize()
    if mutex_handle:
        kernel32.CloseHandle(mutex_handle)
